#peaks.within.genes

gene.hits.regions <- 
  group_by(peaks.within.genes, id, PANTHER_accession, iHS_pop) |> 
  slice_max(ABS_iHS, with_ties=FALSE)

gene.hits.regions <- 
  rename(gene.hits.regions, chrom=seqid, pop=iHS_pop) |>
  arrange(chrom, start, pop)
  
gene.hits.regions <- mutate(gene.hits.regions, loc=paste0(chrom, ":", start, "–", end))
  
write_tsv(x=gene.hits.regions, file="/Volumes/Tigrigobius/tgoby/genes/PANTHER.99/iHS.gene.hits.regions.tab")

saveRDS(object=gene.hits.regions, file="/Volumes/Tigrigobius/tgoby/genes/PANTHER.99/iHS.gene.hits.regions.RDS")

# sets
brewpal2 <- read_tsv(file="/Volumes/Tigrigobius/tgoby/brewpal2.tab")
brewpal2x <- read_tsv(file="/Volumes/Tigrigobius/tgoby/brewpal2x.tab")
#barplot(1:10, col=brewpal2$COLOR2)           

iHS.sets <- 
  list(
    `Del Norte-Humboldt`=filter(gene.hits.regions, pop=="Del Norte-Humboldt")|>pull(id),
    `Mendocino`=filter(gene.hits.regions, pop=="Mendocino")|>pull(id),
    `Santa Barbara`=filter(gene.hits.regions, pop=="Santa Barbara")|>pull(id))

candidates <- unique(c(iHS.sets[[1]], iHS.sets[[2]], iHS.sets[[3]])) |> length()

gg.sets_iHS <- 
  ggvenn(
    data=iHS.sets, 
    digits=0,
    stroke_size=0.5, 
    set_name_size=4.5,
    text_size=4,
#    fill_color=brewpal2$COLOR1[c(8,6,4)], 
    fill_color=rep("white", 3), 
    fill_alpha=1,
    stroke_color=rep(x=brewpal2$COLOR1[c(8,6,4)], times=100), 
    stroke_alpha=1,
#    stroke_alpha=0.67,
    auto_scale=FALSE) + 
  labs(title=paste0(candidates, " Candidate Genes (iHS)"), tag="c)") + 
  theme(plot.caption=element_text(size=13, hjust=0.5), plot.title=element_text(size=15, hjust=0.5), plot.tag=element_text(size=15))
#gg.sets_iHS

ggsave(plot=gg.sets_iHS, filename="/Volumes/Tigrigobius/tgoby/iHS/selscan/gmap/iHS.genes.venn.png", bg="white", device=png, width=5, height=5, units="in", dpi=300)
ggsave(plot=gg.sets_iHS, filename="/Volumes/Tigrigobius/tgoby/iHS/selscan/gmap/iHS.genes.venn.pdf", bg="white", device=cairo_pdf, width=5, height=5, units="in")
